import { quote, claim } from "./claim-office.js";

describe("Claim Office - Quote", () => {
  it("should return 5 G for an empty item list (processing fee only)", () => {
    const customer = { yearsWithMHPCO: 0 };
    const items: never[] = [];
    const contractIndex = 0;
    const premium = quote(customer, items, contractIndex);
    expect(premium).toBe(5);
  });
  it.todo("should return base premium plus processing fee for a single sword");
  it.todo("should return base premium plus processing fee for a single potion");
  it.todo("should return sum of base premiums plus processing fee for multiple items");
  it.todo("should apply +50% cursed surcharge on the cursed item's base premium");
  it.todo("should apply +30% surcharge for highly enchanted item (enchantment >= 5)");
  it.todo("should apply both cursed and high enchantment surcharges on the same item");
  it.todo("should apply -20% loyalty discount on policy base premium for customer >= 2 years");
  it.todo("should apply +10% first insurance surcharge on policy base premium");
  it.todo("should apply -15% follow-up contract discount on policy base premium");
  it.todo("should apply multiple policy-wide modifiers in correct order");
  it.todo("should round up the final premium in MHPCO's favor");
  it.todo("should return 25 G base premium per component (rune or moonstone)");
  it.todo("should return 60 G for a block of exactly 3 alike components");
});

describe("Claim Office - Claim", () => {
  it.todo("should reimburse full damage minus 100 G deductible for a standard item");
  it.todo("should apply 100 G deductible per each damaged item");
  it.todo("should cap total payout at 2x the insurance sum of the policy");
  it.todo("should reimburse at 50% for items with enchantment >= 8");
  it.todo("should fully reimburse dragon material items");
  it.todo("should apply 50% rule when item has both enchantment >= 8 and dragon material");
  it.todo("should round down the payout in MHPCO's favor");
});

